    /// Parsing a well-formed test_plan JSON blob returns the expected steps.
    #[test]
    fn parse_test_plan_steps_happy_path() {
        let raw = r#"{"steps":[
            {"kind":"run","cmd":"cargo test"},
            {"kind":"pull","cmd":"coord pull-artifact abc","label":"binary"},
            {"kind":"verify","check":"no panic in stderr"}
        ],"blockers":[]}"#;
        let steps = parse_test_plan_steps(raw).expect("should parse");
        assert_eq!(steps.len(), 3);
        assert_eq!(steps[0].kind, "run");
        assert_eq!(steps[0].cmd.as_deref(), Some("cargo test"));
        assert_eq!(steps[1].kind, "pull");
        assert_eq!(steps[1].label.as_deref(), Some("binary"));
        assert_eq!(steps[2].kind, "verify");
        assert_eq!(steps[2].check.as_deref(), Some("no panic in stderr"));
        assert!(steps[2].cmd.is_none());
    }

    /// Malformed JSON returns None gracefully (no panic).
    #[test]
    fn parse_test_plan_steps_malformed_returns_none() {
        assert!(parse_test_plan_steps("not json at all").is_none());
        assert!(parse_test_plan_steps("{}").is_none()); // missing "steps"
        assert!(parse_test_plan_steps("null").is_none());
    }

    /// Empty steps array returns Some(vec![]).
    #[test]
    fn parse_test_plan_steps_empty_array() {
        let raw = r#"{"steps":[],"blockers":["need hardware"]}"#;
        let steps = parse_test_plan_steps(raw).expect("should parse");
        assert!(steps.is_empty());
    }

    /// Extra keys in step objects are silently ignored (forward-compat).
    #[test]
    fn parse_test_plan_steps_extra_keys_ignored() {
        let raw = r#"{"steps":[{"kind":"run","cmd":"pytest","future_key":"x"}],"blockers":[]}"#;
        let steps = parse_test_plan_steps(raw).expect("should parse");
        assert_eq!(steps.len(), 1);
        assert_eq!(steps[0].kind, "run");
    }

    /// #349 bug-guard: `chars().take(N)` must not panic when truncating at a
    /// multi-byte UTF-8 boundary.  Previously the code used `&s[..N]` which
    /// panics when N falls inside a multi-byte sequence.
    #[test]
    fn truncate_unicode_at_boundary_does_not_panic() {
        // "こんにちは" — each character is 3 bytes in UTF-8.
        // Byte length is 15; character count is 5.
        // A naïve &s[..8] would split "に" (starts at byte 6, ends at byte 9).
        let s = "こんにちは世界";
        // char-safe truncation at 4 chars.
        let truncated: String = s.chars().take(4).collect();
        assert_eq!(truncated, "こんにち", "should take 4 full characters");
        assert_eq!(truncated.chars().count(), 4);
        // Same logic as used in stage_content_test and other render paths.
        let wide = "A̐éö̲\u{20000}"; // combining chars + surrogate-range codepoint
        let safe: String = wide.chars().take(2).collect();
        assert_eq!(safe.chars().count(), 2);
    }

    /// `read_git_branch_head` returns None for non-existent repo dirs.
    #[test]
    fn read_git_branch_head_missing_dir_returns_none() {
        let result = read_git_branch_head(std::path::Path::new("/nonexistent/repo"), "main");
        assert!(result.is_none());
    }

    /// `read_git_branch_head` reads a loose ref file.
    #[test]
    fn read_git_branch_head_reads_loose_ref() {
        // Use the thread ID to make the directory name unique so parallel test
        // runs cannot collide on a shared /tmp path.
        let tid = format!("{:?}", std::thread::current().id()).replace(['(', ')'], "");
        let tmp = std::env::temp_dir().join(format!("coord-tui-test-git-loose-{}", tid));
        let refs_dir = tmp.join(".git").join("refs").join("heads");
        std::fs::create_dir_all(&refs_dir).unwrap();
        let sha = "abcdef1234567890abcdef1234567890abcdef12";
        std::fs::write(refs_dir.join("my-branch"), format!("{}\n", sha)).unwrap();

        let result = read_git_branch_head(&tmp, "my-branch");
        assert_eq!(result.as_deref(), Some(sha));

        // Clean up (best-effort).
        let _ = std::fs::remove_dir_all(&tmp);
    }

    /// `read_git_branch_head` falls back to packed-refs when loose file missing.
    #[test]
    fn read_git_branch_head_reads_packed_refs() {
        let tid = format!("{:?}", std::thread::current().id()).replace(['(', ')'], "");
        let tmp = std::env::temp_dir().join(format!("coord-tui-test-git-packed-{}", tid));
        let git_dir = tmp.join(".git");
        std::fs::create_dir_all(&git_dir).unwrap();
        let sha = "1111222233334444555566667777888899990000";
        let packed = format!(
            "# pack-refs with: peeled fully-peeled\n{} refs/heads/packed-branch\n",
            sha
        );
        std::fs::write(git_dir.join("packed-refs"), packed).unwrap();

        let result = read_git_branch_head(&tmp, "packed-branch");
        assert_eq!(result.as_deref(), Some(sha));

        let _ = std::fs::remove_dir_all(&tmp);
    }

    // ── #410: board_row_status_badge ─────────────────────────────────────

    /// `board_row_status_badge` maps lifecycle strings to the correct
    /// per-row letter badges.  This is a pure function — test it directly
    /// so the mapping table can't silently regress.
    #[test]
    fn board_row_status_badge_mapping() {
        // Backlog: blank
        assert!(board_row_status_badge("").is_none(), "unknown/empty → None");
        assert!(
            board_row_status_badge("backlog").is_none(),
            "backlog → None"
        );

        // Refining / refined → "R"
        let r_badge = board_row_status_badge("refining");
        assert!(r_badge.is_some(), "refining → Some");
        assert_eq!(r_badge.unwrap().text, "R");

        let refined_badge = board_row_status_badge("refined");
        assert!(refined_badge.is_some(), "refined → Some");
        assert_eq!(
            refined_badge.unwrap().text,
            "R",
            "refined should fold into R just like refining"
        );

        // In-flight → "A"
        let a_badge = board_row_status_badge("in-flight");
        assert!(a_badge.is_some(), "in-flight → Some");
        assert_eq!(a_badge.unwrap().text, "A");

        // Completed → "D"
        let d_badge = board_row_status_badge("completed");
        assert!(d_badge.is_some(), "completed → Some");
        assert_eq!(d_badge.unwrap().text, "D");
    }

    // ── #410: dispatch_board_row_direct success path ─────────────────────

    /// `dispatch_board_row_direct` should spawn `coord assign <machine>
    /// <repo> <issue>` when a reachable machine exists.  The existing test
    /// (context_menu_activate_fires_action_and_dismisses) only covers the
    /// "no reachable machine" failure path.  This test covers the happy path.
    #[test]
    fn dispatch_board_row_direct_success_path_spawns_coord_assign() {
        // Build an app that has one reachable machine configured for "repo-a".
        let mut app = CoordApp {
            data: BoardData {
                machines: vec![Machine {
                    name: "test-machine".to_string(),
                    host: String::new(),
                    reachable: true,
                    active_count: 0,
                    repos: vec!["repo-a".to_string()],
                    version: None,
                    worktree_bytes: 0,
                }],
                ..BoardData::default()
            },
            ..make_test_app(BoardData::default())
        };

        // Before: command runner must be idle.
        assert!(!app.command_runner.is_running(), "runner should start idle");

        let before_toasts = app.toasts.len();
        let target = board_target(Some(42), BoardRowLifecycle::Backlog);
        let dispatched = app.dispatch_board_row_direct(&target);

        // dispatch_board_row_direct returns true on success.
        assert!(
            dispatched,
            "dispatch_board_row_direct must return true on success"
        );

        // A command was actually spawned (coord assign …).
        assert!(
            app.command_runner.is_running(),
            "coord assign must be running after successful dispatch",
        );

        // Exactly one toast (the "dispatched → test-machine" confirmation).
        assert_eq!(
            app.toasts.len(),
            before_toasts + 1,
            "exactly one success toast expected",
        );
        let toast_body = app.toasts.last().unwrap().0.body.to_string();
        assert!(
            toast_body.contains("42") && toast_body.contains("test-machine"),
            "toast should mention issue #42 and machine, got: {toast_body:?}",
        );
    }

